const http = require('http');

function mcpRequest(host, port, body, sessionId) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const headers = { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'Content-Length': Buffer.byteLength(data) };
    if (sessionId) headers['Mcp-Session-Id'] = sessionId;
    const req = http.request({ hostname: host, port, path: '/mcp', method: 'POST', headers }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        const lines = body.split('\n');
        let jsonData = '';
        for (const line of lines) { if (line.startsWith('data: ')) jsonData = line.substring(6); }
        resolve({ status: res.statusCode, headers: res.headers, body: jsonData || body });
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

async function callMcpTool(host, port, toolName, toolArgs) {
  const init = await mcpRequest(host, port, { jsonrpc: '2.0', id: 1, method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'n8n-workflow', version: '1.0' } } });
  const sid = init.headers['mcp-session-id'];
  await mcpRequest(host, port, { jsonrpc: '2.0', method: 'notifications/initialized' }, sid);
  const result = await mcpRequest(host, port, { jsonrpc: '2.0', id: 3, method: 'tools/call', params: { name: toolName, arguments: toolArgs } }, sid);
  const parsed = JSON.parse(result.body);
  return parsed.result?.content?.[0]?.text || 'Error: ' + JSON.stringify(parsed.error);
}

const j = $input.first().json;
const results = [];

const podsOutput = await callMcpTool(j.mcpHost, parseInt(j.mcpPort, 10), 'pods_list_in_namespace', { namespace: 'openshift-lightspeed' });
results.push('=== MCP Pods (openshift-lightspeed) ===\n' + podsOutput);

const gwOutput = await callMcpTool(j.mcpHost, parseInt(j.mcpPort, 10), 'resources_list', { apiVersion: 'gateway.networking.k8s.io/v1', resource: 'gateways' });
results.push('\n=== Gateways (all namespaces) ===\n' + gwOutput);

const routesOutput = await callMcpTool(j.mcpHost, parseInt(j.mcpPort, 10), 'resources_list', { apiVersion: 'gateway.networking.k8s.io/v1', resource: 'httproutes' });
results.push('\n=== HTTPRoutes (all namespaces) ===\n' + routesOutput);

const rlpOutput = await callMcpTool(j.mcpHost, parseInt(j.mcpPort, 10), 'resources_list', { apiVersion: 'kuadrant.io/v1', resource: 'ratelimitpolicies' });
results.push('\n=== RateLimitPolicies (all namespaces) ===\n' + rlpOutput);

return [{ json: { ...j, mcpOutput: results.join('\n') } }];

const http = require('http');
const input = $input.first().json;
const litellmHost = input.litellmHost;
const litellmPort = parseInt(input.litellmPort, 10);
const litellmApiKey = input.litellmApiKey || '';
const mcpOutputFull = input.mcpOutput || '';
const mcpOutput = mcpOutputFull.length > 1200 ? mcpOutputFull.substring(0, 1200) + '\n[... truncated]' : mcpOutputFull;
const systemPrompt = 'Analyze MCP and API Gateway infrastructure status. Data includes MCP server pods in openshift-lightspeed namespace, Kubernetes Gateways, HTTPRoutes, and RateLimitPolicies. Reply with: 1) HTML table of MCP pods with name, status, and ready state, 2) HTML table of Gateways with name, namespace, gatewayClass, and programmed status, 3) HTML table of HTTPRoutes with name, namespace, and hostnames, 4) HTML table of RateLimitPolicies with name, namespace, and status, 5) Overall infrastructure health (Healthy/Degraded/Critical). Be concise, use inline CSS.';
const requestBody = JSON.stringify({ model: 'llama-scout-17b', messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: mcpOutput }], temperature: 0.3, max_tokens: 1024 });
return new Promise((resolve, reject) => {
  const req = http.request({ hostname: litellmHost, port: litellmPort, path: '/v1/chat/completions', method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + litellmApiKey, 'Content-Length': Buffer.byteLength(requestBody) } }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        let rawAI = parsed.choices?.[0]?.message?.content || 'AI analysis unavailable';
        rawAI = rawAI.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
        const aiAnalysis = rawAI.length > 1800 ? rawAI.substring(0, 1800) + '\n[... truncated]' : rawAI;
        resolve([{ json: { ...input, aiAnalysis, aiModel: parsed.model || 'llama-scout-17b' } }]);
      } catch (e) { resolve([{ json: { ...input, aiAnalysis: 'AI analysis failed: ' + e.message, aiModel: 'error' } }]); }
    });
  });
  req.on('error', (e) => { resolve([{ json: { ...input, aiAnalysis: 'AI service unavailable: ' + e.message, aiModel: 'unreachable' } }]); });
  req.write(requestBody);
  req.end();
});

